import{_ as t,o as s,c as i,ae as a}from"./chunks/framework.CFUUUNbY.js";const m=JSON.parse('{"title":"Clonning All.This ‚Äã","description":"","frontmatter":{},"headers":[],"relativePath":"old/Understanding Git Submodules.md","filePath":"old/Understanding Git Submodules.md"}'),n={name:"old/Understanding Git Submodules.md"};function o(l,e,h,u,r,d){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="clonning-all-this-‚Äã" tabindex="-1">Clonning All.This ‚Äã <a class="header-anchor" href="#clonning-all-this-‚Äã" aria-label="Permalink to &quot;Clonning All.This ‚Äã&quot;">‚Äã</a></h1><p><strong>As a Contributor</strong> you have access to the full structure of All.This.</p><h3 id="setup-for-development-‚Äã" tabindex="-1">Setup for Development ‚Äã <a class="header-anchor" href="#setup-for-development-‚Äã" aria-label="Permalink to &quot;Setup for Development ‚Äã&quot;">‚Äã</a></h3><ul><li><strong>Clone the Repository</strong></li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/neurons-me/all.this.git</span></span></code></pre></div><h2 id="_1-understanding-git-submodules-‚Äã" tabindex="-1">1. Understanding Git Submodules ‚Äã <a class="header-anchor" href="#_1-understanding-git-submodules-‚Äã" aria-label="Permalink to &quot;1. Understanding Git Submodules ‚Äã&quot;">‚Äã</a></h2><p>Each submodule is a fully independent Git repository embedded within the ‚Äúparent‚Äù repository. The parent repo stores a reference (a specific commit SHA) of the submodule, not the entire submodule‚Äôs commit history. When you commit and push changes inside a submodule, you also need to commit an update in the parent repository (because the parent repo‚Äôs pointer/reference to that submodule changes).</p><h2 id="common-pain-points-‚Äã" tabindex="-1">Common Pain Points ‚Äã <a class="header-anchor" href="#common-pain-points-‚Äã" aria-label="Permalink to &quot;Common Pain Points ‚Äã&quot;">‚Äã</a></h2><p>Having to commit/push in each submodule:</p><p>You must enter each submodule folder, commit changes, push them, then go back to the parent repo, update the submodule reference, and commit/push that reference.</p><h2 id="cloning-only-one-submodule-‚Äã" tabindex="-1">Cloning only one submodule: ‚Äã <a class="header-anchor" href="#cloning-only-one-submodule-‚Äã" aria-label="Permalink to &quot;Cloning only one submodule: ‚Äã&quot;">‚Äã</a></h2><p>If you want just one submodule locally, you can clone that submodule‚Äôs repo directly (since it‚Äôs an independent repo). However, it won‚Äôt automatically track changes in the parent or other submodules. <strong>Detecting when submodules are behind:</strong></p><p>You can run <code>git submodule status</code> or <code>git submodule foreach git status</code> to see if you‚Äôre behind or have uncommitted changes.</p><p>You must manually coordinate pulling/pushing each submodule to stay in sync.</p><ul><li><h3 id="committing-pushing-all-submodules-at-once-‚Äã" tabindex="-1">Committing &amp; Pushing All Submodules at Once ‚Äã <a class="header-anchor" href="#committing-pushing-all-submodules-at-once-‚Äã" aria-label="Permalink to &quot;Committing &amp; Pushing All Submodules at Once ‚Äã&quot;">‚Äã</a></h3></li></ul><p>You can automate the repetitive commit/push steps with commands like:</p><p><strong>From your parent repo:</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> submodule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> foreach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --recursive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;git add . &amp;&amp; git commit -m &quot;Commit from script&quot; &amp;&amp; git push&#39;</span></span></code></pre></div><p>Then you‚Äôd do:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># In the parent repo, stage the submodule reference changes:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Update submodule references&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span></span></code></pre></div><p>Note: This command attempts to commit and push every submodule with the same commit message, which might not be ideal if each submodule needs a unique message or different logic. It is, however, a quick automation hack.</p><h2 id="_3-cloning-only-a-single-submodule-‚Äã" tabindex="-1">3. Cloning Only a Single Submodule ‚Äã <a class="header-anchor" href="#_3-cloning-only-a-single-submodule-‚Äã" aria-label="Permalink to &quot;3. Cloning Only a Single Submodule ‚Äã&quot;">‚Äã</a></h2><p>If you want to work on just one submodule:</p><ul><li><strong>Clone that submodule‚Äôs repository directly</strong> (since it is a standalone repo). Example: <code>bash git clone git@github.com:your-org/that-one-submodule.git </code></li><li>Make changes, commit, push.</li><li>To update the reference in the parent repo: You‚Äôd pull the new submodule commits into the parent (with <code>git submodule update --remote --merge that-one-submodule</code> or manually pulling in that folder).</li><li>Then commit the parent repo to update the pointer.</li></ul><p><strong>But</strong> you lose the convenience of seeing how your changes integrate with the rest of the parent repo in real-time.</p>`,25)])])}const c=t(n,[["render",o]]);export{m as __pageData,c as default};
